script:
frappe.ui.form.on("Applicant Document", {
    attachment(frm, cdt, cdn) {
        // When student uploads a file, auto-set status to Submitted
        let row = locals[cdt][cdn];
        if (row.attachment) {
            frappe.model.set_value(cdt, cdn, "document_status", "Submitted");
        }
    }
});
